/* == EXEMPLE =======================================
 * writev pour écrire un log structuré
 * timestamp + message en un seul appel
 * ================================================= */
void example_writev(void) {
    char p[] = "/tmp/kf_ex_iov_XXXXXX";
    int fd = mkstemp(p);
    if (fd == -1) return;
    unlink(p);
    char ts[] = "[LOG] ";
    char msg[] = "system started";
    struct iovec v[2] = {
        {ts, strlen(ts)},
        {msg, strlen(msg)}
    };
    ssize_t n = writev(fd, v, 2);
    printf("example: wrote %zd bytes\n", n);
    lseek(fd, 0, SEEK_SET);
    char buf[32] = {0};
    read(fd, buf, sizeof(buf) - 1);
    printf("example: %s\n", buf);
    close(fd);
}
/* Resultat: wrote 20 bytes, [LOG] system started */

